1516	pub fn set_metatable(state: &mut LuaState, objindex: i32) -> Result<bool, LuaError> {
1517	    // C: api_checknelems(L, 1);
1518	    let top = state.top_idx();
1519	    let mt_val = state.get_at(top - 1);
1520	    // C: if (ttisnil(s2v(L->top.p - 1))) mt = NULL; else mt = hvalue(...)
1521	    let mt: Option<GcRef<LuaTable>> = if matches!(mt_val, LuaValue::Nil) {
1522	        None
1523	    } else {
1524	        debug_assert!(matches!(mt_val, LuaValue::Table(_)), "table expected");
1525	        if let LuaValue::Table(t) = mt_val {
1526	            Some(t)
1527	        } else {
1528	            None
1529	        }
1530	    };
1531	
1532	    let obj = index_to_value(state, objindex);
1533	    // C: switch (ttype(obj)) { LUA_TTABLE: ... LUA_TUSERDATA: ... default: G(L)->mt[ttype] }
1534	    match obj {
1535	        LuaValue::Table(ref tbl) => {
1536	            if mt.is_some() {
1537	                // C: luaC_objbarrier(L, gcvalue(obj), mt);
1538	                // C: luaC_checkfinalizer(L, gcvalue(obj), mt);
1539	                state.gc().obj_barrier(tbl, mt.as_ref().unwrap());
1540	                // TODO(port): luaC_checkfinalizer
1541	            }
1542	            // C: hvalue(obj)->metatable = mt;
1543	            tbl.set_metatable(mt);
1544	            if tbl.weak_mode() != 0 {
1545	                state
1546	                    .global_mut()
1547	                    .weak_tables_registry
1548	                    .push(std::rc::Rc::downgrade(&tbl.0));
1549	            }
1550	        }
1551	        LuaValue::UserData(ref ud) => {
1552	            if let Some(ref mt_table) = mt {
1553	                state.gc().obj_barrier(ud, mt_table);
1554	                // TODO(port): luaC_checkfinalizer
1555	            }
1556	            ud.set_metatable(mt);
1557	        }
1558	        ref other => {
1559	            let idx = other.base_type() as usize;
1560	            state.global_mut().mt[idx] = mt;
1561	        }
1562	    }
1563	    // C: L->top.p--;
1564	    state.pop();
1565	    Ok(true)
1566	}
