+fn entry_is_weakly_dead_global(
+    k: &LuaValue,
+    v: &LuaValue,
+    mode: u8,
+    all_tables: &[GcRef<LuaTable>],
+) -> bool {
+    let weak_k = (mode & WEAK_KEYS) != 0;
+    let weak_v = (mode & WEAK_VALUES) != 0;
+    if weak_k && is_target_dead_global(k, all_tables) {
+        return true;
